/**
 * In-memory dedupe for `recordUserSeenModal` within a single page load.
 * Not `sessionStorage` — clears on full page refresh.
 */
const dedupedModalPersistIds = new Set<string>();

export const hasDedupedModalPersist = (modalId: string): boolean =>
  dedupedModalPersistIds.has(modalId);

export const markModalPersistDeduped = (modalId: string): void => {
  dedupedModalPersistIds.add(modalId);
};

export const clearModalPersistDeduped = (modalId: string): void => {
  dedupedModalPersistIds.delete(modalId);
};

export const resetPersistDedupe = (): void => {
  dedupedModalPersistIds.clear();
};
